class Solution(object):
    def reverseSubmatrix(self, grid, x, y, k):
        import copy
        g = copy.deepcopy(grid)
        for col in range(y, y + k):
            rows = [g[r][col] for r in range(x, x + k)]
            rows.reverse()
            for i, r in enumerate(range(x, x + k)):
                g[r][col] = rows[i]
        return g
